defineGetter(req, 'host', function host(){
  var trust = this.app.get('trust proxy fn');
  var val = this.get('X-Forwarded-Host');

  if (!val || !trust(this.socket.remoteAddress, 0)) {
    val = this.get('Host');
  } else if (val.indexOf(',') !== -1) {
    // Note: X-Forwarded-Host is normally only ever a
    //       single value, but this is to be safe.
    val = val.substring(0, val.indexOf(',')).trimRight()
  }

  return val || undefined;
});

defineGetter(req, 'hostname', function hostname(){
  var host = this.host;

  if (!host) return;

  // IPv6 literal support
  var offset = host[0] === '['
    ? host.indexOf(']') + 1
    : 0;
  var index = host.indexOf(':', offset);

  return index !== -1
    ? host.substring(0, index)
    : host;
});

var swaggerInitFunction = function (swaggerDoc, opts) {
  var swaggerInitFile = jsTplString.toString().replace('<% swaggerOptions %>', stringify(opts))
  return function (req, res, next) {
    if (trimQuery(req.url).endsWith('/package.json')) {
      res.sendStatus(404)
    } else if (trimQuery(req.url).endsWith('/swagger-ui-init.js')) {
      if (req.swaggerDoc) {
        opts.swaggerDoc = req.swaggerDoc
        swaggerInitFile = jsTplString.toString().replace('<% swaggerOptions %>', stringify(opts))
      }
      res.set('Content-Type', 'application/javascript')
      res.send(swaggerInitFile)
    } else {
      next()
    }
  }
}

getRouter(): express.Router {
  const router = Router();

  router.use(bodyParser.raw({ type: '*/*' }));

  router.post('/immediate/entities', async (req, res) => {
    if (!this.connection) {
      throw new Error(`Service is not yet initialized`);
    }
    const deferred = await this.getRequestBodyEntities(req);
    await this.connection.applyMutation({
      type: 'delta',
      added: deferred,
      removed: [],
    });
    res.status(201).end();
  });

  router.put('/immediate/entities', async (req, res) => {
    if (!this.connection) {
      throw new Error(`Service is not yet initialized`);
    }
    const deferred = await this.getRequestBodyEntities(req);
    await this.connection.applyMutation({
      type: 'full',
      entities: deferred,
    });
    res.status(201).end();
  });

  return router;
}

installPathParams(app: Application | Router, context: OpenApiContext): void {
  const pathParams: string[] = [];
  for (const route of context.routes) {
    if (route.pathParams.length > 0) {
      pathParams.push(...route.pathParams);
    }
  }

  // install param on routes with paths
  const uniqPathParams = [...new Set(pathParams)]
  for (const p of uniqPathParams) {
    app.param(
      p,
      (
        req: OpenApiRequest,
        res: Response,
        next: NextFunction,
        value: any,
        name: string,
      ) => {
        const openapi = <OpenApiRequestMetadata>req.openapi;
        if (openapi?.pathParams) {
          const { pathParams } = openapi;
          // override path params
          req.params[name] = pathParams[name] || req.params[name];
        }
        next();
      },
    );
  }
}

function createRedirectDirectoryListener () {
  return function redirect (res) {
    if (this.hasTrailingSlash()) {
      this.error(404)
      return
    }

    // get original URL
    var originalUrl = parseUrl.original(this.req)

    // append trailing slash
    originalUrl.path = null
    originalUrl.pathname = collapseLeadingSlashes(originalUrl.pathname + '/')

    // reformat the URL
    var loc = encodeUrl(url.format(originalUrl))
    var doc = createHtmlDocument('Redirecting', 'Redirecting to ' + escapeHtml(loc))

    // send redirect response
    res.statusCode = 301
    res.setHeader('Content-Type', 'text/html; charset=UTF-8')
    res.setHeader('Content-Length', Buffer.byteLength(doc))
    res.setHeader('Content-Security-Policy', "default-src 'none'")
    res.setHeader('X-Content-Type-Options', 'nosniff')
    res.setHeader('Location', loc)
    res.end(doc)
  }
}

private async handleHttpResponseMessage(
  message: HttpResponseMessage,
  res: express.Response,
): Promise<void> {
  this.copyHeadersTo(message.headers, res);

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  if (message.content !== undefined) {
    this.copyHeadersTo(message.content.headers, res);

    res
      .status(message.statusCode)
      // If the content is a number, ensure we change it to a string, else our content is
      // treated as a statusCode rather than as the content of the Response
      .send(await message.content.readAsync());
  } else {
    res.sendStatus(message.statusCode);
  }
}

function issecure(req, trustProxy) {
  // socket is https server
  if (req.connection && req.connection.encrypted) {
    return true;
  }

  // do not trust proxy
  if (trustProxy === false) {
    return false;
  }

  // no explicit trust; try req.secure from express
  if (trustProxy !== true) {
    return req.secure === true
  }

  // read the proto from x-forwarded-proto header
  var header = req.headers['x-forwarded-proto'] || '';
  var index = header.indexOf(',');
  var proto = index !== -1
    ? header.substr(0, index).toLowerCase().trim()
    : header.toLowerCase().trim()

  return proto === 'https';
}

const contentSecurityPolicy: ContentSecurityPolicy =
  function contentSecurityPolicy(
    options: Readonly<ContentSecurityPolicyOptions> = {},
  ): (
    req: IncomingMessage,
    res: ServerResponse,
    next: (err?: Error) => void,
  ) => void {
    const headerName = options.reportOnly
      ? "Content-Security-Policy-Report-Only"
      : "Content-Security-Policy";

    const normalizedDirectives = normalizeDirectives(options);

    return function contentSecurityPolicyMiddleware(
      req: IncomingMessage,
      res: ServerResponse,
      next: (error?: Error) => void,
    ) {
      const result = getHeaderValue(req, res, normalizedDirectives);
      if (result instanceof Error) {
        next(result);
      } else {
        res.setHeader(headerName, result);
        next();
      }
    };
  };

export async function runAllChains(
  req: Request,
  chains: readonly ValidationChainLike[],
  runOpts?: ContextRunningOptions,
): Promise<ResultWithContext[]> {
  const promises: Promise<ResultWithContext>[] = [];
  for (const chain of chains) {
    const bails = chain.builder.build().bail;
    if (bails) {
      await Promise.all(promises);
    }

    const resultPromise = chain.run(req, runOpts);
    promises.push(resultPromise);
    if (bails) {
      const result = await resultPromise;
      if (!result.isEmpty()) {
        break;
      }
    }
  }
  return Promise.all(promises);
}

function expandField(req: Request, field: string, location: Location): FieldInstance[] {
  const originalPath = field;
  const pathToExpand = location === 'headers' ? field.toLowerCase() : field;

  const paths = expandPath(req[location], pathToExpand, []);

  return paths.map(({ path, values }) => {
    const value = path === '' ? req[location] : _.get(req[location], path);
    return {
      location,
      path,
      originalPath,
      pathValues: values,
      value,
    };
  });
}

type PathWithValues = {
  path: string;
  values: readonly (string | string[])[];
};

type Tree = { [K: string]: Tree | undefined };
export const selectUnknownFields = (
  req: Request,
  knownFields: string[],
  locations: Location[],
): UnknownFieldInstance[] => {
  const tree: Tree = {};
  knownFields.forEach(field => {
    const segments = field === '' ? [''] : _.toPath(field);
    pathToTree(segments, tree);
  });

  const instances: UnknownFieldInstance[] = [];
  for (const location of locations) {
    if (req[location] != null) {
      instances.push(...findUnknownFields(location, req[location], tree));
    }
  }

  return instances;
};

private createChain(
  fields: string | string[] = '',
  locations: Location[] = [],
  message?: any,
): CustomValidationChain<this> {
  const middleware = check(fields, locations, message) as CustomValidationChain<this>;

  const boundValidators = Object.fromEntries(
    this.validatorEntries.map(([name, fn]) => [name, () => middleware.custom(fn)]),
  ) as Record<keyof V, () => CustomValidationChain<this>>;

  const boundSanitizers = Object.fromEntries(
    this.sanitizerEntries.map(([name, fn]) => [name, () => middleware.customSanitizer(fn)]),
  ) as Record<keyof S, () => CustomValidationChain<this>>;

  return Object.assign(middleware, boundValidators, boundSanitizers);
}

public _getOrBuildValidator(
  req: OpenApiRequest,
  responses: OpenAPIV3.ResponsesObject,
): { [key: string]: ValidateFunction } {
  // get the request content type - used only to build the cache key
  const contentTypeMeta = ContentType.from(req);
  const contentType = contentTypeMeta.normalize() ?? 'not_provided';

  const openapi = <OpenApiRequestMetadata>req.openapi;
  const key = `${req.method}-${openapi.expressRoute}-${contentType}`;

  let validators = this.validatorsCache[key];
  if (!validators) {
    validators = this.buildValidators(responses, key);
    this.validatorsCache[key] = validators;
  }
  return validators;
}

const setLegacyHeaders = (
	response: Response,
	info: RateLimitInfo,
): void => {
	if (response.headersSent) return

	response.setHeader('X-RateLimit-Limit', info.limit.toString())
	response.setHeader('X-RateLimit-Remaining', info.remaining.toString())

	// If we have a resetTime, also provide the current date to help avoid
	// issues with incorrect clocks.
	if (info.resetTime instanceof Date) {
		response.setHeader('Date', new Date().toUTCString())
		response.setHeader(
			'X-RateLimit-Reset',
			Math.ceil(info.resetTime.getTime() / 1000).toString(),
		)
	}
}

const setDraft6Headers = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
): void => {
	if (response.headersSent) return

	const windowSeconds = Math.ceil(windowMs / 1000)
	const resetSeconds = getResetSeconds(windowMs, info.resetTime)

	response.setHeader('RateLimit-Policy', `${info.limit};w=${windowSeconds}`)
	response.setHeader('RateLimit-Limit', info.limit.toString())
	response.setHeader('RateLimit-Remaining', info.remaining.toString())

	// Set this header only if the store returns a `resetTime`.
	if (typeof resetSeconds === 'number')
		response.setHeader('RateLimit-Reset', resetSeconds.toString())
}

async run(context: Context, value: any, meta: Meta) {
  try {
    const result = this.validator(value, meta);
    const actualResult = await result;
    const isPromise = result?.then;
    const failed = this.negated ? actualResult : !actualResult;

    // A promise that was resolved only adds an error if negated.
    // Otherwise it always succeeds
    if ((!isPromise && failed) || (isPromise && this.negated)) {
      context.addError({ type: 'field', message: this.message, value, meta });
    }
  } catch (err) {
    if (this.negated) {
      return;
    }

    context.addError({
      type: 'field',
      message: this.message || (err instanceof Error ? err.message : err),
      value,
      meta,
    });
  }
}

async run(context: Context, value: any, meta: Meta) {
  const { path, location } = meta;

  const runCustomSanitizer = async () => {
    const sanitizerValue = this.sanitizer(value, meta);
    return Promise.resolve(sanitizerValue);
  };

  if (this.custom) {
    const newValue = await runCustomSanitizer();
    context.setData(path, newValue, location);
    return;
  }
  const values = Array.isArray(value) ? value : [value];
  const newValues = values.map(value => {
    return (this.sanitizer as StandardSanitizer)(this.stringify(value), ...this.options);
  });

  // We get only the first value of the array if the original value was wrapped.
  context.setData(path, values !== value ? newValues[0] : newValues, location);
}

export function matchedData<T extends object = Record<string, any>>(
  req: Request,
  options: Partial<MatchedDataOptions> = {},
): T {
  const internalReq: InternalRequest = req;

  const fieldExtractor = createFieldExtractor(options.includeOptionals !== true);
  const validityFilter = createValidityFilter(options.onlyValidData);
  const locationFilter = createLocationFilter(options.locations);

  return _(internalReq[contextsKey])
    .flatMap(fieldExtractor)
    .filter(validityFilter)
    .map(field => field.instance)
    .filter(locationFilter)
    .reduce((state, instance) => _.set(state, instance.path, instance.value), {} as T);
}

function DigestStrategy(options, secret, validate) {
  if (typeof options == 'function') {
    validate = secret;
    secret = options;
    options = {};
  }
  if (!secret) throw new Error('HTTP Digest authentication strategy requires a secret function');

  passport.Strategy.call(this);
  this.name = 'digest';
  this._secret = secret;
  this._validate = validate;
  this._realm = options.realm || 'Users';
  if (options.domain) {
    this._domain = (Array.isArray(options.domain)) ? options.domain : [ options.domain ];
  }
  this._opaque = options.opaque;
  this._algorithm = options.algorithm;
  if (options.qop) {
    this._qop = (Array.isArray(options.qop)) ? options.qop : [ options.qop ];
  }
}

async factory({ config }) {
  const rootLoggerConfig = getRootLoggerConfig(config);

  const logger = WinstonLogger.create({
    meta: {
      service: 'backstage',
      ...rootLoggerConfig.meta,
    },
    level: process.env.LOG_LEVEL || rootLoggerConfig.level || 'info',
    format:
      process.env.NODE_ENV === 'production'
        ? format.json()
        : WinstonLogger.colorFormat(),
    transports: [new transports.Console()],
  });

  const secretEnumerator = await createConfigSecretEnumerator({ logger });
  logger.addRedactions(secretEnumerator(config));
  config.subscribe?.(() => logger.addRedactions(secretEnumerator(config)));

  logger.setLevelOverrides(rootLoggerConfig.overrides ?? []);
  config.subscribe?.(() =>
    logger.setLevelOverrides(getRootLoggerConfig(config).overrides ?? []),
  );

  return logger;
}

export function check(
  fields: string | string[] = '',
  locations: Location[] = [],
  message?: FieldMessageFactory | ErrorMessage,
): ValidationChain {
  const builder = new ContextBuilder()
    .setFields(Array.isArray(fields) ? fields : [fields])
    .setLocations(locations)
    .setMessage(message);
  const runner = new ContextRunnerImpl(builder);

  const middleware = async (req: InternalRequest, _res: any, next: (err?: any) => void) => {
    try {
      await runner.run(req);
      next();
    } catch (e) {
      next(e);
    }
  };

  return Object.assign(
    middleware,
    bindAll(runner),
    bindAll(new SanitizersImpl(builder, middleware as any)),
    bindAll(new ValidatorsImpl(builder, middleware as any)),
    bindAll(new ContextHandlerImpl(builder, middleware as any)),
    { builder },
  );
}

app.init = function init() {
  var router = null;

  this.cache = Object.create(null);
  this.engines = Object.create(null);
  this.settings = Object.create(null);

  this.defaultConfiguration();

  // Setup getting to lazily add base router
  Object.defineProperty(this, 'router', {
    configurable: true,
    enumerable: true,
    get: function getrouter() {
      if (router === null) {
        router = new Router({
          caseSensitive: this.enabled('case sensitive routing'),
          strict: this.enabled('strict routing')
        });
      }

      return router;
    }
  });
};

export function reconstructFieldPath(segments: readonly string[]): string {
  return segments.reduce((prev, segment) => {
    let part = '';
    segment = segment === '\\*' ? '*' : segment;

    // TODO: Handle brackets?
    if (segment.includes('.')) {
      // Special char key access
      part = `["${segment}"]`;
    } else if (/^\d+$/.test(segment)) {
      // Index access
      part = `[${segment}]`;
    } else if (prev) {
      // Object key access
      part = `.${segment}`;
    } else {
      // Top level key
      part = segment;
    }

    return prev + part;
  }, '');
}

function getHeaderValue(
  req: IncomingMessage,
  res: ServerResponse,
  normalizedDirectives: Readonly<NormalizedDirectives>,
): string | Error {
  const result: string[] = [];

  for (const [directiveName, rawDirectiveValue] of normalizedDirectives) {
    let directiveValue = "";
    for (const element of rawDirectiveValue) {
      if (typeof element === "function") {
        const newElement = element(req, res);
        assertDirectiveValueEntryIsValid(directiveName, newElement);
        directiveValue += " " + newElement;
      } else {
        directiveValue += " " + element;
      }
    }

    if (directiveValue) {
      assertDirectiveValueIsValid(directiveName, directiveValue);
      result.push(`${directiveName}${directiveValue}`);
    } else {
      result.push(directiveName);
    }
  }

  return result.join(";");
}

function tokenSet() {
  const contextCache = weakRef(this);
  const session = contextCache.req[contextCache.config.session.name];

  if (!session || !('id_token' in session)) {
    return undefined;
  }

  const cachedTokenSet = weakRef(session);

  if (!('value' in cachedTokenSet)) {
    const { id_token, access_token, refresh_token, token_type, expires_at } =
      session;
    cachedTokenSet.value = new TokenSet({
      id_token,
      access_token,
      refresh_token,
      token_type,
      expires_at,
    });
  }

  return cachedTokenSet.value;
}

